input.old_string:
check() {
  local desc=$1; shift
  if "$@" &>/dev/null; then
    echo "  $desc"; PASS=$((PASS + 1))
  else
    echo "  $desc"; FAIL=$((FAIL + 1))
  fi
}

input.new_string:
check() {
  local desc=$1; shift
  if "$@" &>/dev/null; then
    echo "  ✅ $desc"; PASS=$((PASS + 1))
  else
    echo "  ❌ $desc"; FAIL=$((FAIL + 1))
  fi
}

# Helper for checks that need pipes (pipes can't be passed as arguments to check)
check_grep() {
  local desc=$1
  local haystack=$2
  local needle=$3
  if echo "$haystack" | grep -qi "$needle"; then
    echo "  ✅ $desc"; PASS=$((PASS + 1))
  else
    echo "  ❌ $desc"; FAIL=$((FAIL + 1))
  fi
}

